import Foundation
import CryptoKit
import Security

class CryptoWallet {
    private var privateKey: Data?
    private var publicKey: Data?
    
    init() {
        generateKeyPair()
    }
    
    func generateKeyPair() {
        let keyPair = SecKeyCreateRandomKey([
            kSecAttrKeyType: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits: 256
        ] as CFDictionary, nil)
        
        if let key = keyPair {
            let publicKeyData = SecKeyCopyExternalRepresentation(key, nil)
            let privateKeyData = SecKeyCopyExternalRepresentation(key, nil)
            
            self.privateKey = Data(publicKeyData!)
            self.publicKey = Data(privateKeyData!)
        }
    }
    
    func signTransaction(transaction: String) -> Data? {
        guard let privateKey = self.privateKey else { return nil }
        
        let message = transaction.data(using: .utf8)!
        let signature = SecKeyCreateSignature(privateKey as CFTypeRef, .ecdsaSignatureDigestX962, message as CFData, nil)
        
        return signature as Data?
    }
    
    func getPublicKey() -> String {
        return publicKey?.base64EncodedString() ?? ""
    }
    
    func getPrivateKey() -> String {
        return privateKey?.base64EncodedString() ?? ""
    }
}

class BlockchainClient {
    private let baseURL = "https://api.blockchain.info"
    
    func sendTransaction(transaction: String, signature: Data) async throws -> String {
        let url = URL(string: "\(baseURL)/send")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = transaction.data(using: .utf8)
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let (data, response) = try await URLSession.shared.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        return String(data: data, encoding: .utf8) ?? ""
    }
    
    func getBalance(address: String) async throws -> Double {
        let url = URL(string: "\(baseURL)/balance?address=\(address)")!
        let (data, response) = try await URLSession.shared.data(for: url)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        return json?["balance"] as? Double ?? 0.0
    }
}

class WalletManager {
    private let wallet = CryptoWallet()
    private let blockchain = BlockchainClient()
    
    func createTransaction(to: String, amount: Double) async throws -> String {
        let transaction = """
        {
            "to": "\(to)",
            "amount": \(amount),
            "from": "\(wallet.getPublicKey())"
        }
        """
        
        guard let signature = wallet.signTransaction(transaction: transaction) else {
            throw URLError(.badServerResponse)
        }
        
        return try await blockchain.sendTransaction(transaction: transaction, signature: signature)
    }
    
    func getBalance() async throws -> Double {
        return try await blockchain.getBalance(address: wallet.getPublicKey())
    }
    
    func getWalletAddress() -> String {
        return wallet.getPublicKey()
    }
}